import json

def find_counterexample():
    # Define the set of vertices V and the special subset L
    # V = {0, 1, 2, 3}
    # L = {0, 1, 2}
    V_nodes = list(range(4))
    L_set = {0, 1, 2}

    # Construct the graph G
    G = nx.Graph()
    G.add_nodes_from(V_nodes)

    # G is a complete graph K_4 on V_nodes
    for i in V_nodes:
        for j in V_nodes:
            if i < j:
                G.add_edge(i, j)

    # --- Verify all premises of the conjecture ---

    # Premise 1: hL_card_eq_3 : L.card = 3
    if len(L_set) != 3:
        return None 

    # Premise 2: hG_is_clique_L : G.isClique L
    if not nx.is_clique(G, L_set):
        return None

    # Premise 3: hG_clique_number_eq_4 : G.cliqueNumber = 4
    g_clique_number = nx.graph_clique_number(G)
    if g_clique_number != 4:
        return None

    # Premise 4: h_all_k4_contain_L : ∀ (C : Finset V), C.card = 4 → G.isClique C → L.subset C
    all_k4_contain_L = True
    found_4_clique = False
    for clique in nx.find_cliques(G):
        if len(clique) == 4:
            found_4_clique = True
            if not L_set.issubset(set(clique)):
                all_k4_contain_L = False
                break

    if not found_4_clique: # Should not happen if g_clique_number == 4
        return None

    if not all_k4_contain_L:
        return None

    # --- All premises are satisfied. Now construct G' and check its clique number ---

    G_prime = nx.Graph()
    G_prime.add_nodes_from(V_nodes)

    # Edges (u,v) are in G' if they are in G AND (u is not in L_set OR v is not in L_set)
    # This is equivalent to NOT (u is in L_set AND v is in L_set)
    for u, v in G.edges():
        if not (u in L_set and v in L_set):
            G_prime.add_edge(u, v)

    # Calculate the clique number of G'
    g_prime_clique_number = nx.graph_clique_number(G_prime)

    # The conjecture states G_prime.cliqueNumber should be 3.
    # If it's not 3, we have found a counterexample.
    if g_prime_clique_number != 3:
        counter_example_data = {
            "V": sorted(V_nodes),
            "L": sorted(list(L_set)),
            "G_edges": sorted([sorted(list(edge)) for edge in G.edges()]),
            "G_prime_edges": sorted([sorted(list(edge)) for edge in G_prime.edges()]),
            "G_clique_number": g_clique_number,
            "G_prime_clique_number": g_prime_clique_number,
            "conjecture_expected_G_prime_clique_number": 3
        }
        return json.dumps(counter_example_data, separators=(',', ':'))

    return None

